import { getEnvAsBoolean, getOptionalEnv, requireEnvInProd } from '@/lib/env'

export type AvatarRenderEngineJobState =
  | 'queued'
  | 'processing'
  | 'completed'
  | 'failed'
  | 'error'
  | 'unknown'

export interface AvatarRenderEngineRenderRequest {
  text: string
  avatar_id: string
  preset?: string
  resolution?: string
  fps?: number
}

export interface AvatarRenderEngineRenderResponse {
  success: boolean
  job_id: string
  message?: string
  status?: AvatarRenderEngineJobState | string
}

export interface AvatarRenderEngineJobStatusResponse {
  success?: boolean
  job_id?: string
  status: AvatarRenderEngineJobState | string
  message?: string
  progress?: number
  video_filename?: string
  filename?: string
  video_url?: string
  output_url?: string
  error?: string
  error_message?: string
}

export class AvatarRenderEngineHTTPError extends Error {
  readonly status: number
  readonly url: string
  readonly responseBody?: string

  constructor(params: { message: string; status: number; url: string; responseBody?: string }) {
    super(params.message)
    this.name = 'AvatarRenderEngineHTTPError'
    this.status = params.status
    this.url = params.url
    this.responseBody = params.responseBody
  }
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null
}

function normalizeJobState(value: unknown): AvatarRenderEngineJobState {
  if (typeof value !== 'string') return 'unknown'
  const v = value.toLowerCase()
  if (v === 'queued') return 'queued'
  if (v === 'processing') return 'processing'
  if (v === 'completed' || v === 'done' || v === 'success') return 'completed'
  if (v === 'failed' || v === 'error') return 'failed'
  return 'unknown'
}

function shouldRetry(status: number | null): boolean {
  if (status === null) return true // network / timeout
  if (status === 429) return true
  return status >= 500 && status <= 599
}

async function sleep(ms: number, signal?: AbortSignal): Promise<void> {
  if (ms <= 0) return
  await new Promise<void>((resolve, reject) => {
    const timer = setTimeout(resolve, ms)

    if (signal) {
      if (signal.aborted) {
        clearTimeout(timer)
        reject(new Error('Sleep aborted'))
        return
      }
      signal.addEventListener(
        'abort',
        () => {
          clearTimeout(timer)
          reject(new Error('Sleep aborted'))
        },
        { once: true }
      )
    }
  })
}

export interface AvatarRenderEngineClientOptions {
  baseUrl?: string
  enabled?: boolean
  timeoutMs?: number
  maxAttempts?: number
  baseDelayMs?: number
  maxDelayMs?: number
}

export class AvatarRenderEngineClient {
  private readonly baseUrl: string
  private readonly enabled: boolean
  private readonly timeoutMs: number
  private readonly maxAttempts: number
  private readonly baseDelayMs: number
  private readonly maxDelayMs: number

  constructor(options: AvatarRenderEngineClientOptions = {}) {
    const enabled =
      typeof options.enabled === 'boolean'
        ? options.enabled
        : getEnvAsBoolean('AVATAR_RENDER_ENGINE_ENABLED', false)

    const baseUrl =
      options.baseUrl ||
      (enabled
        ? requireEnvInProd('AVATAR_RENDER_ENGINE_URL', 'http://localhost:8765')
        : getOptionalEnv('AVATAR_RENDER_ENGINE_URL', ''))

    this.enabled = enabled
    this.baseUrl = baseUrl.replace(/\/+$/, '')
    this.timeoutMs = options.timeoutMs ?? 20_000
    this.maxAttempts = options.maxAttempts ?? 4
    this.baseDelayMs = options.baseDelayMs ?? 300
    this.maxDelayMs = options.maxDelayMs ?? 5_000
  }

  isEnabled(): boolean {
    return this.enabled && this.baseUrl.length > 0
  }

  getBaseUrl(): string {
    return this.baseUrl
  }

  getVideoDownloadUrl(filename: string): string {
    const clean = filename.replace(/^\/+/, '')
    return `${this.baseUrl}/output/videos/${encodeURIComponent(clean)}`
  }

  async createRenderJob(payload: AvatarRenderEngineRenderRequest): Promise<AvatarRenderEngineRenderResponse> {
    if (!this.isEnabled()) {
      throw new Error('Avatar Render Engine is disabled (set AVATAR_RENDER_ENGINE_ENABLED=true and AVATAR_RENDER_ENGINE_URL)')
    }

    const url = `${this.baseUrl}/api/avatars/render`
    const json = await this.requestJsonWithRetry(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    })

    if (!isRecord(json)) {
      throw new Error('Invalid response from Avatar Render Engine: expected JSON object')
    }

    const jobId = typeof json.job_id === 'string' ? json.job_id : undefined
    if (!jobId) {
      throw new Error('Invalid response from Avatar Render Engine: missing job_id')
    }

    return {
      success: json.success === true,
      job_id: jobId,
      message: typeof json.message === 'string' ? json.message : undefined,
      status: typeof json.status === 'string' ? normalizeJobState(json.status) : undefined,
    }
  }

  async getJobStatus(jobId: string): Promise<AvatarRenderEngineJobStatusResponse> {
    if (!this.isEnabled()) {
      throw new Error('Avatar Render Engine is disabled (set AVATAR_RENDER_ENGINE_ENABLED=true and AVATAR_RENDER_ENGINE_URL)')
    }

    const safeId = encodeURIComponent(jobId)
    const url = `${this.baseUrl}/api/avatars/status/${safeId}`
    const json = await this.requestJsonWithRetry(url, { method: 'GET' })

    if (!isRecord(json)) {
      return { status: 'unknown', error: 'Invalid JSON response (expected object)' }
    }

    const status = normalizeJobState(json.status)
    const progress = typeof json.progress === 'number' ? json.progress : undefined

    return {
      success: typeof json.success === 'boolean' ? json.success : undefined,
      job_id: typeof json.job_id === 'string' ? json.job_id : jobId,
      status: typeof json.status === 'string' ? (status === 'unknown' ? json.status : status) : 'unknown',
      message: typeof json.message === 'string' ? json.message : undefined,
      progress,
      video_filename: typeof json.video_filename === 'string' ? json.video_filename : undefined,
      filename: typeof json.filename === 'string' ? json.filename : undefined,
      video_url: typeof json.video_url === 'string' ? json.video_url : undefined,
      output_url: typeof json.output_url === 'string' ? json.output_url : undefined,
      error: typeof json.error === 'string' ? json.error : undefined,
      error_message: typeof json.error_message === 'string' ? json.error_message : undefined,
    }
  }

  private async requestJsonWithRetry(url: string, init: RequestInit): Promise<unknown> {
    let attempt = 0
    let lastError: unknown

    while (attempt < this.maxAttempts) {
      const controller = new AbortController()
      const timeout = setTimeout(() => controller.abort(), this.timeoutMs)
      const requestInit: RequestInit = {
        ...init,
        signal: controller.signal,
      }

      try {
        const res = await fetch(url, requestInit)
        clearTimeout(timeout)

        if (!res.ok) {
          const bodyText = await safeReadText(res)
          const err = new AvatarRenderEngineHTTPError({
            message: `Avatar Render Engine HTTP ${res.status} (${res.statusText})`,
            status: res.status,
            url,
            responseBody: bodyText,
          })

          if (shouldRetry(res.status)) {
            lastError = err
          } else {
            throw err
          }
        } else {
          return await safeReadJson(res)
        }
      } catch (error: unknown) {
        clearTimeout(timeout)
        // fetch throws TypeError on network failures, and AbortError on abort
        const status = error instanceof AvatarRenderEngineHTTPError ? error.status : null
        if (!shouldRetry(status)) throw error
        lastError = error
      }

      attempt += 1
      if (attempt >= this.maxAttempts) break

      const backoff = Math.min(this.maxDelayMs, this.baseDelayMs * Math.pow(2, attempt - 1))
      const jitter = Math.floor(Math.random() * 100)
      await sleep(backoff + jitter)
    }

    throw lastError instanceof Error ? lastError : new Error('Avatar Render Engine request failed')
  }
}

async function safeReadText(res: Response): Promise<string | undefined> {
  try {
    const text = await res.text()
    return text.length > 0 ? text.slice(0, 10_000) : undefined
  } catch {
    return undefined
  }
}

async function safeReadJson(res: Response): Promise<unknown> {
  const contentType = res.headers.get('content-type') || ''
  if (!contentType.toLowerCase().includes('application/json')) {
    const text = await safeReadText(res)
    return text ?? null
  }
  try {
    return await res.json()
  } catch {
    const text = await safeReadText(res)
    return text ?? null
  }
}
